messages.content:
Use a parent-child schema with sessions as the root entity. Here's the design:

```sql
CREATE TABLE sessions (
    id            TEXT PRIMARY KEY,
    project       TEXT NOT NULL,
    started_at    INTEGER NOT NULL,
    ended_at      INTEGER,
    summary       TEXT,
    message_count INTEGER NOT NULL DEFAULT 0,
    total_tokens  INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE messages (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id      TEXT NOT NULL REFERENCES sessions(id),
    seq             INTEGER NOT NULL,
    role            TEXT NOT NULL CHECK(role IN ('system','user','assistant','tool')),
    content         TEXT NOT NULL,
    tool_calls      TEXT,       -- JSON array of tool call objects, nullable
    tool_call_id    TEXT,       -- For tool-result messages, links back to the call
    tokens_estimated INTEGER NOT NULL DEFAULT 0,
    timestamp       INTEGER NOT NULL
);

CREATE INDEX idx_messages_session ON messages(session_id);
CREATE INDEX idx_sessions_project ON sessions(project);
```

In Rust, the SessionManager owns the connection:

```rust
pub struct SessionManager {
    conn: rusqlite::Connection,
    current_session_id: Option<String>,
    project: String,
}

impl SessionManager {
    pub fn open(db_path: &Path, project: &str) -> Result<Self> {
        let conn = rusqlite::Connection::open(db_path)?;
        conn.pragma_update(None, "journal_mode", "WAL")?;
        conn.pragma_update(None, "foreign_keys", "ON")?;
        conn.execute_batch(/* schema above */)?;
        Ok(Self { conn, current_session_id: None, project: project.to_string() })
    }

    pub fn save_message(&self, role: Role, content: &str, tool_calls: Option<&[ToolCall]>) -> Result<()> {
        let session_id = self.current_session_id.as_ref()
            .context("No active session")?;
        let seq = self.next_seq(session_id)?;
        let tc_json = tool_calls.map(|tcs| serde_json::to_string(tcs).unwrap_or_default());

        self.conn.execute(
            "INSERT INTO messages (session_id, seq, role, content, tool_calls, tokens_estimated, timestamp)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)",
            rusqlite::params![session_id, seq, role_str(&role), content, tc_json,
                estimate_tokens(content), now_epoch()],
        )?;
        Ok(())
    }
}
```

Key decisions: (1) WAL mode for concurrent reads during writes. (2) `seq` column preserves message ordering regardless of timestamp granularity. (3) Tool calls stored as JSON since their schema varies per tool. (4) Foreign key enforcement catches orphaned messages.

Sessions without an `ended_at` timestamp are incomplete. On startup, detect and offer to resume:

```rust
impl SessionManager {
    /// Find the most recent incomplete session for this project.
    pub fn find_resumable_session(&self) -> Result<Option<ResumableSession>> {
        let result = self.conn.query_row(
            "SELECT id, started_at, message_count FROM sessions
             WHERE project = ?1 AND ended_at IS NULL
             ORDER BY started_at DESC LIMIT 1",
            [&self.project],
            |row| Ok(ResumableSession {
                id: row.get(0)?,
                started_at: row.get(1)?,
                message_count: row.get(2)?,
            }),
        );

        match result {
            Ok(session) => Ok(Some(session)),
            Err(rusqlite::Error::QueryReturnedNoRows) => Ok(None),
            Err(e) => Err(e.into()),
        }
    }

    /// Resume a previous session by loading its messages.
    pub fn resume_session(&mut self, session_id: &str) -> Result<Vec<Message>> {
        // Verify the session exists and belongs to this project
        let project: String = self.conn.query_row(
            "SELECT project FROM sessions WHERE id = ?1",
            [session_id],
            |row| row.get(0),
        ).context("session not found")?;

        if project != self.project {
            anyhow::bail!("session belongs to a different project");
        }

        self.current_session_id = Some(session_id.to_string());
        self.load_messages_for_session(session_id)
    }
}
```

The crash-safe guarantee comes from WAL mode: each `INSERT` is durable once `execute` returns. Even if the process is killed immediately after, the message is committed. The missing `ended_at` is the signal that the session didn't terminate cleanly.

Use a single events table with a flexible payload column, plus materialized views for common queries:

```sql
CREATE TABLE events (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id  TEXT NOT NULL,
    project     TEXT NOT NULL,
    event_type  TEXT NOT NULL,
    timestamp   INTEGER NOT NULL,
    payload     TEXT NOT NULL,  -- JSON
    -- Denormalized fields for fast queries:
    tool_name   TEXT,           -- Set when event_type = 'tool_invoked'
    duration_ms INTEGER         -- Set for timed events
);

CREATE INDEX idx_events_session ON events(session_id);
CREATE INDEX idx_events_type_ts ON events(event_type, timestamp);
CREATE INDEX idx_events_tool ON events(tool_name) WHERE tool_name IS NOT NULL;
```

In Rust, use a typed event enum that serializes to JSON:

```rust
#[derive(Debug, serde::Serialize)]
#[serde(tag = "type")]
pub enum AnalyticsEvent {
    ToolInvoked {
        tool_name: String,
        arguments_summary: String,
        duration_ms: u64,
        success: bool,
    },
    ModelResponse {
        tokens_used: u32,
        stop_reason: String,
        latency_ms: u64,
    },
    UserFeedback {
        sentiment: String,  // "positive", "negative", "correction"
        message: Option<String>,
    },
    SessionStart {
        project: String,
        resumed: bool,
    },
    ContextCompaction {
        messages_before: u32,
        messages_after: u32,
        strategy: String,
    },
}

pub struct AnalyticsStore {
    conn: rusqlite::Connection,
}

impl AnalyticsStore {
    pub fn record(&self, session_id: &str, project: &str, event: &AnalyticsEvent) -> Result<()> {
        let (event_type, tool_name, duration_ms) = match event {
            AnalyticsEvent::ToolInvoked { tool_name, duration_ms, .. } =>
                ("tool_invoked", Some(tool_name.as_str()), Some(*duration_ms as i64)),
            AnalyticsEvent::ModelResponse { latency_ms, .. } =>
                ("model_response", None, Some(*latency_ms as i64)),
            AnalyticsEvent::UserFeedback { .. } => ("user_feedback", None, None),
            AnalyticsEvent::SessionStart { .. } => ("session_start", None, None),
            AnalyticsEvent::ContextCompaction { .. } => ("context_compaction", None, None),
        };

        let payload = serde_json::to_string(event)?;
        self.conn.execute(
            "INSERT INTO events (session_id, project, event_type, timestamp, payload, tool_name, duration_ms)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?7)",
            rusqlite::params![session_id, project, event_type, now_epoch(), payload, tool_name, duration_ms],
        )?;
        Ok(())
    }
}
```

The denormalized columns (`tool_name`, `duration_ms`) avoid parsing JSON for common queries like "average tool latency in the last hour." The JSON payload preserves full event detail for ad-hoc analysis.

Facts need upsert semantics and project isolation:

```sql
CREATE TABLE facts (
    id        INTEGER PRIMARY KEY AUTOINCREMENT,
    project   TEXT NOT NULL,
    key       TEXT NOT NULL,
    value     TEXT NOT NULL,
    confidence REAL NOT NULL DEFAULT 1.0,
    source    TEXT NOT NULL DEFAULT 'extracted',  -- 'extracted', 'explicit', 'inferred'
    stored_at INTEGER NOT NULL,
    updated_at INTEGER NOT NULL
);

-- Unique constraint enables upsert
CREATE UNIQUE INDEX idx_facts_project_key ON facts(project, key);
```

The Rust layer handles validation and upsert:

```rust
pub struct FactStore {
    conn: rusqlite::Connection,
    project: String,
}

impl FactStore {
    pub fn upsert(&self, key: &str, value: &str, confidence: f32, source: &str) -> Result<()> {
        // Validate inputs
        if key.is_empty() || key.len() > 1024 {
            anyhow::bail!("fact key must be 1-1024 bytes");
        }
        if value.len() > 1_048_576 {
            anyhow::bail!("fact value exceeds 1MB limit");
        }
        if key.contains('\0') || value.contains('\0') {
            anyhow::bail!("null bytes not allowed in facts");
        }

        let now = now_epoch();
        self.conn.execute(
            "INSERT INTO facts (project, key, value, confidence, source, stored_at, updated_at)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6, ?6)
             ON CONFLICT(project, key) DO UPDATE SET
                value = excluded.value,
                confidence = excluded.confidence,
                source = excluded.source,
                updated_at = excluded.updated_at",
            rusqlite::params![self.project, key, value, confidence, source, now],
        )?;
        Ok(())
    }

    /// Retrieve all facts for the current project, formatted for LLM injection.
    pub fn format_for_prompt(&self, max_bytes: usize) -> Result<String> {
        let mut stmt = self.conn.prepare(
            "SELECT key, value FROM facts WHERE project = ?1 ORDER BY confidence DESC, key"
        )?;
        let facts: Vec<(String, String)> = stmt.query_map([&self.project], |row| {
            Ok((row.get::<_, String>(0)?, row.get::<_, String>(1)?))
        })?.collect::<std::result::Result<_, _>>()?;

        let mut output = String::from("## Known facts about this user\n");
        for (key, value) in facts {
            let line = format!("- {}: {}\n", key, value);
            if output.len() + line.len() > max_bytes { break; }
            output.push_str(&line);
        }
        Ok(output)
    }
}
```

Key design: (1) `ON CONFLICT ... DO UPDATE` gives atomic upsert without separate SELECT+INSERT. (2) Confidence scores let you prioritize explicit user statements over inferred facts. (3) The `source` column tracks whether the user stated something directly or the system inferred it. (4) `format_for_prompt` has a byte cap to prevent context window overflow.

Keep it flat -- plugins are a small dataset, so a single table with JSON for the flexible bits works best:

```sql
CREATE TABLE plugins (
    name        TEXT PRIMARY KEY,
    version     TEXT NOT NULL,
    description TEXT NOT NULL DEFAULT '',
    author      TEXT,
    enabled     INTEGER NOT NULL DEFAULT 1,
    sandbox     TEXT NOT NULL DEFAULT 'standard',  -- 'none', 'standard', 'strict'
    manifest    TEXT NOT NULL,  -- Full TOML manifest as text
    installed_at INTEGER NOT NULL,
    last_used   INTEGER,
    error_count INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE plugin_permissions (
    plugin_name TEXT NOT NULL REFERENCES plugins(name) ON DELETE CASCADE,
    permission  TEXT NOT NULL,
    granted     INTEGER NOT NULL DEFAULT 0,
    granted_at  INTEGER,
    PRIMARY KEY (plugin_name, permission)
);
```

Rust implementation:

```rust
pub struct PluginRegistry {
    conn: rusqlite::Connection,
}

impl PluginRegistry {
    pub fn register(&self, manifest: &PluginManifest) -> Result<()> {
        // Validate plugin name (security: prevent path traversal via name)
        if !manifest.name.chars().all(|c| c.is_alphanumeric() || c == '-' || c == '_') {
            anyhow::bail!("plugin name contains invalid characters: {}", manifest.name);
        }

        let manifest_toml = toml::to_string(manifest)?;
        self.conn.execute(
            "INSERT OR REPLACE INTO plugins (name, version, description, author, manifest, installed_at)
             VALUES (?1, ?2, ?3, ?4, ?5, ?6)",
            rusqlite::params![
                manifest.name, manifest.version, manifest.description,
                manifest.author, manifest_toml, now_epoch()
            ],
        )?;

        // Register declared permissions (not yet granted)
        for perm in &manifest.permissions {
            self.conn.execute(
                "INSERT OR IGNORE INTO plugin_permissions (plugin_name, permission)
                 VALUES (?1, ?2)",
                rusqlite::params![manifest.name, perm],
            )?;
        }

        Ok(())
    }

    pub fn is_permitted(&self, plugin_name: &str, permission: &str) -> Result<bool> {
        let granted: bool = self.conn.query_row(
            "SELECT granted FROM plugin_permissions
             WHERE plugin_name = ?1 AND permission = ?2",
            rusqlite::params![plugin_name, permission],
            |row| row.get(0),
        ).unwrap_or(false);
        Ok(granted)
    }

    pub fn auto_disable_on_error(&self, plugin_name: &str, threshold: i32) -> Result<bool> {
        self.conn.execute(
            "UPDATE plugins SET error_count = error_count + 1 WHERE name = ?1",
            [plugin_name],
        )?;
        let count: i32 = self.conn.query_row(
            "SELECT error_count FROM plugins WHERE name = ?1",
            [plugin_name],
            |row| row.get(0),
        )?;
        if count >= threshold {
            self.conn.execute(
                "UPDATE plugins SET enabled = 0 WHERE name = ?1",
                [plugin_name],
            )?;
            return Ok(true); // Plugin was disabled
        }
        Ok(false)
    }
}
```

The `ON DELETE CASCADE` on permissions means uninstalling a plugin automatically cleans up its permissions. The `error_count` with auto-disable prevents a buggy plugin from crashing the system repeatedly.

Use three related tables: sessions track what happened, patterns track recurring behaviors, and rules are the generated outputs:

```sql
CREATE TABLE sessions (
    id              TEXT PRIMARY KEY,
    project         TEXT NOT NULL,
    timestamp       INTEGER NOT NULL,
    task_description TEXT NOT NULL,
    outcome         TEXT NOT NULL CHECK(outcome IN ('success','partial','failure','abandoned')),
    user_feedback   TEXT,
    total_tokens    INTEGER NOT NULL DEFAULT 0,
    retries         INTEGER NOT NULL DEFAULT 0
);

CREATE TABLE tool_calls (
    id                INTEGER PRIMARY KEY AUTOINCREMENT,
    session_id        TEXT NOT NULL REFERENCES sessions(id),
    seq               INTEGER NOT NULL,
    tool_name         TEXT NOT NULL,
    arguments_summary TEXT NOT NULL,
    result_type       TEXT NOT NULL CHECK(result_type IN ('success','error','timeout','cancelled')),
    error_message     TEXT,
    duration_ms       INTEGER NOT NULL DEFAULT 0
);

CREATE INDEX idx_tool_calls_session ON tool_calls(session_id);

CREATE TABLE generated_rules (
    id          INTEGER PRIMARY KEY AUTOINCREMENT,
    name        TEXT NOT NULL UNIQUE,
    content     TEXT NOT NULL,
    source_type TEXT NOT NULL CHECK(source_type IN ('pattern','failure','feedback')),
    confidence  REAL NOT NULL DEFAULT 0.5,
    times_applied INTEGER NOT NULL DEFAULT 0,
    times_helpful INTEGER NOT NULL DEFAULT 0,
    enabled     INTEGER NOT NULL DEFAULT 1,
    created_at  INTEGER NOT NULL,
    last_applied INTEGER
);
```

The rule generation query analyzes recent sessions:

```rust
impl EvolutionStore {
    /// Find tool call patterns across recent sessions.
    pub fn find_patterns(&self, project: &str, min_occurrences: u32) -> Result<Vec<Pattern>> {
        let mut stmt = self.conn.prepare(
            "SELECT tool_name, COUNT(*) as cnt,
                    AVG(CASE WHEN result_type = 'success' THEN 1.0 ELSE 0.0 END) as success_rate
             FROM tool_calls tc
             JOIN sessions s ON tc.session_id = s.id
             WHERE s.project = ?1 AND s.timestamp > ?2
             GROUP BY tool_name
             HAVING cnt >= ?3
             ORDER BY cnt DESC"
        )?;

        let cutoff = now_epoch() - 7 * 24 * 3600; // Last 7 days
        let patterns = stmt.query_map(
            rusqlite::params![project, cutoff, min_occurrences],
            |row| Ok(Pattern {
                tool_name: row.get(0)?,
                occurrences: row.get(1)?,
                success_rate: row.get(2)?,
            }),
        )?.collect::<std::result::Result<Vec<_>, _>>()?;

        Ok(patterns)
    }

    /// Auto-disable rules that consistently don't help.
    pub fn prune_ineffective_rules(&self, min_applications: u32, min_helpful_ratio: f64) -> Result<u32> {
        let affected = self.conn.execute(
            "UPDATE generated_rules SET enabled = 0
             WHERE times_applied >= ?1
             AND CAST(times_helpful AS REAL) / times_applied < ?2
             AND enabled = 1",
            rusqlite::params![min_applications, min_helpful_ratio],
        )?;
        Ok(affected as u32)
    }
}
```

The evolution loop: (1) After each session, record outcome and tool calls. (2) Periodically analyze patterns (e.g., "file_read always precedes file_write"). (3) Generate rules from patterns. (4) Apply rules in future sessions. (5) Track whether rules helped. (6) Disable rules with low helpful ratios. This creates a feedback loop where the system genuinely improves over time.

Here's a rules schema with built-in lifecycle management:

```sql
CREATE TABLE evolution_rules (
    id              INTEGER PRIMARY KEY AUTOINCREMENT,
    name            TEXT NOT NULL UNIQUE,
    content         TEXT NOT NULL,
    -- Confidence management
    confidence      REAL NOT NULL DEFAULT 0.5,
    -- Source tracking
    source_type     TEXT NOT NULL,  -- 'pattern', 'failure_analysis', 'user_feedback'
    source_sessions TEXT NOT NULL,  -- JSON array of session IDs that contributed
    -- Application tracking
    times_applied   INTEGER NOT NULL DEFAULT 0,
    times_helpful   INTEGER NOT NULL DEFAULT 0,
    times_harmful   INTEGER NOT NULL DEFAULT 0,
    -- Lifecycle
    enabled         INTEGER NOT NULL DEFAULT 1,
    created_at      INTEGER NOT NULL,
    last_applied    INTEGER,
    expires_at      INTEGER  -- NULL = never expires
);

CREATE INDEX idx_rules_active ON evolution_rules(enabled, confidence DESC)
    WHERE enabled = 1;
```

The confidence scoring logic:

```rust
const MAX_RULES: usize = 20;
const MIN_CONFIDENCE: f64 = 0.3;
const CONFIDENCE_BOOST: f64 = 0.1;
const CONFIDENCE_PENALTY: f64 = 0.15;

impl EvolutionStore {
    /// Record that a rule was applied and whether it helped.
    pub fn record_application(&self, rule_id: i64, was_helpful: bool) -> Result<()> {
        let (helpful_inc, harmful_inc) = if was_helpful { (1, 0) } else { (0, 1) };

        self.conn.execute(
            "UPDATE evolution_rules SET
                times_applied = times_applied + 1,
                times_helpful = times_helpful + ?1,
                times_harmful = times_harmful + ?2,
                last_applied = ?3,
                confidence = MIN(1.0, MAX(0.0,
                    confidence + CASE WHEN ?4 THEN ?5 ELSE -?6 END
                ))
             WHERE id = ?7",
            rusqlite::params![
                helpful_inc, harmful_inc, now_epoch(),
                was_helpful, CONFIDENCE_BOOST, CONFIDENCE_PENALTY, rule_id
            ],
        )?;

        // Auto-disable if confidence drops below threshold
        self.conn.execute(
            "UPDATE evolution_rules SET enabled = 0
             WHERE id = ?1 AND confidence < ?2",
            rusqlite::params![rule_id, MIN_CONFIDENCE],
        )?;

        Ok(())
    }

    /// Get active rules, respecting the cap and expiration.
    pub fn get_active_rules(&self) -> Result<Vec<Rule>> {
        let now = now_epoch();
        let mut stmt = self.conn.prepare(
            "SELECT id, name, content, confidence FROM evolution_rules
             WHERE enabled = 1
             AND (expires_at IS NULL OR expires_at > ?1)
             ORDER BY confidence DESC
             LIMIT ?2"
        )?;

        let rules = stmt.query_map(
            rusqlite::params![now, MAX_RULES as i64],
            |row| Ok(Rule {
                id: row.get(0)?,
                name: row.get(1)?,
                content: row.get(2)?,
                confidence: row.get(3)?,
            }),
        )?.collect::<std::result::Result<Vec<_>, _>>()?;

        Ok(rules)
    }

    /// Expire old rules and prune disabled ones.
    pub fn cleanup(&self) -> Result<u32> {
        let now = now_epoch();
        let expired = self.conn.execute(
            "UPDATE evolution_rules SET enabled = 0
             WHERE expires_at IS NOT NULL AND expires_at <= ?1 AND enabled = 1",
            [now],
        )?;
        // Delete rules disabled for more than 30 days
        let deleted = self.conn.execute(
            "DELETE FROM evolution_rules
             WHERE enabled = 0 AND last_applied < ?1",
            [now - 30 * 24 * 3600],
        )?;
        Ok((expired + deleted) as u32)
    }
}
```

The confidence system creates natural selection: helpful rules trend toward 1.0, unhelpful rules drop below 0.3 and get disabled. The cap at 20 active rules prevents context window bloat. Expired rules are soft-deleted (disabled) first, then permanently removed after 30 days.

SQLite supports `ALTER TABLE ... ADD COLUMN` for simple additions. Use a version-tracked migration system:

```rust
pub struct Migrator {
    conn: rusqlite::Connection,
}

impl Migrator {
    pub fn run(&self) -> Result<()> {
        // Create migrations tracking table
        self.conn.execute_batch(
            "CREATE TABLE IF NOT EXISTS schema_version (
                version INTEGER PRIMARY KEY,
                applied_at INTEGER NOT NULL
            );"
        )?;

        let current = self.current_version()?;

        if current < 1 {
            self.apply(1, "ALTER TABLE facts ADD COLUMN tags TEXT DEFAULT '[]'")?;
        }
        if current < 2 {
            self.apply(2, "CREATE INDEX IF NOT EXISTS idx_facts_tags ON facts(tags)")?;
        }

        Ok(())
    }

    fn current_version(&self) -> Result<i64> {
        self.conn.query_row(
            "SELECT COALESCE(MAX(version), 0) FROM schema_version",
            [],
            |row| row.get(0),
        ).map_err(|_| anyhow::anyhow!("failed to read schema version"))
    }

    fn apply(&self, version: i64, sql: &str) -> Result<()> {
        let tx = self.conn.unchecked_transaction()?;
        tx.execute_batch(sql)?;
        tx.execute(
            "INSERT INTO schema_version (version, applied_at) VALUES (?1, ?2)",
            rusqlite::params![version, now_epoch()],
        )?;
        tx.commit()?;
        eprintln!("Applied migration v{}", version);
        Ok(())
    }
}
```

Each migration runs in a transaction so it either fully applies or fully rolls back. The `schema_version` table prevents re-running migrations. Call `Migrator::run()` on every app startup -- it's idempotent.

For destructive schema changes, use the four-step table rebuild pattern:

```rust
if current < 3 {
    // Migration 3: Rename 'key' to 'fact_key' and add NOT NULL constraint
    self.apply(3, "
        -- Step 1: Create new table with desired schema
        CREATE TABLE facts_new (
            id          INTEGER PRIMARY KEY AUTOINCREMENT,
            project     TEXT NOT NULL,
            fact_key    TEXT NOT NULL,
            value       TEXT NOT NULL,
            confidence  REAL NOT NULL DEFAULT 1.0,
            tags        TEXT DEFAULT '[]',
            stored_at   INTEGER NOT NULL,
            updated_at  INTEGER NOT NULL
        );

        -- Step 2: Copy data
        INSERT INTO facts_new (id, project, fact_key, value, confidence, tags, stored_at, updated_at)
        SELECT id, project, key, value, COALESCE(confidence, 1.0), COALESCE(tags, '[]'),
               stored_at, COALESCE(updated_at, stored_at)
        FROM facts;

        -- Step 3: Drop old table
        DROP TABLE facts;

        -- Step 4: Rename new table
        ALTER TABLE facts_new RENAME TO facts;

        -- Recreate indexes
        CREATE UNIQUE INDEX idx_facts_project_key ON facts(project, fact_key);
    ")?;
}
```

Critical: wrap this in a transaction (which `apply` does). If the process crashes between DROP and RENAME, the data would be lost without a transaction. Also note the `COALESCE` calls -- they handle rows where the new columns don't have values yet.

Create an FTS5 table that mirrors your content table, then populate it:

```rust
if current < 4 {
    self.apply(4, "
        -- Create FTS5 virtual table for full-text search
        CREATE VIRTUAL TABLE IF NOT EXISTS facts_fts USING fts5(
            fact_key,
            value,
            content=facts,
            content_rowid=id
        );

        -- Populate FTS index from existing data
        INSERT INTO facts_fts(rowid, fact_key, value)
        SELECT id, fact_key, value FROM facts;

        -- Triggers to keep FTS in sync with the content table
        CREATE TRIGGER facts_ai AFTER INSERT ON facts BEGIN
            INSERT INTO facts_fts(rowid, fact_key, value)
            VALUES (new.id, new.fact_key, new.value);
        END;

        CREATE TRIGGER facts_ad AFTER DELETE ON facts BEGIN
            INSERT INTO facts_fts(facts_fts, rowid, fact_key, value)
            VALUES ('delete', old.id, old.fact_key, old.value);
        END;

        CREATE TRIGGER facts_au AFTER UPDATE ON facts BEGIN
            INSERT INTO facts_fts(facts_fts, rowid, fact_key, value)
            VALUES ('delete', old.id, old.fact_key, old.value);
            INSERT INTO facts_fts(rowid, fact_key, value)
            VALUES (new.id, new.fact_key, new.value);
        END;
    ")?;
}
```

Query it:
```rust
pub fn search_facts(&self, query: &str, limit: u32) -> Result<Vec<FactMatch>> {
    // Sanitize FTS5 query: escape special chars
    let safe_query = query.replace('"', """");
    let fts_query = format!(""{}"", safe_query);

    let mut stmt = self.conn.prepare(
        "SELECT f.fact_key, f.value, f.confidence,
                highlight(facts_fts, 1, '<b>', '</b>') as snippet
         FROM facts_fts fts
         JOIN facts f ON f.id = fts.rowid
         WHERE facts_fts MATCH ?1 AND f.project = ?2
         ORDER BY rank
         LIMIT ?3"
    )?;

    let matches = stmt.query_map(
        rusqlite::params![fts_query, self.project, limit],
        |row| Ok(FactMatch {
            key: row.get(0)?,
            value: row.get(1)?,
            confidence: row.get(2)?,
            snippet: row.get(3)?,
        }),
    )?.collect::<std::result::Result<Vec<_>, _>>()?;

    Ok(matches)
}
```

The `content=facts` option makes it a contentless FTS table -- it stores only the index, not a copy of the data. The triggers keep the FTS index synchronized on every INSERT, UPDATE, and DELETE. The FTS5 'delete' command is the special syntax for removing entries from the index.

Add the column, then backfill in batches to avoid holding a giant transaction:

```rust
impl Migrator {
    fn migrate_add_embeddings(&self) -> Result<()> {
        // Step 1: Add column (instant, no data movement)
        self.apply(5, "ALTER TABLE chunks ADD COLUMN embedding_v2 BLOB")?;

        // Step 2: Backfill in batches (outside migration transaction)
        let total: i64 = self.conn.query_row(
            "SELECT COUNT(*) FROM chunks WHERE embedding_v2 IS NULL AND embedding IS NOT NULL",
            [], |row| row.get(0),
        )?;

        let batch_size = 100;
        let mut processed = 0i64;

        loop {
            let ids: Vec<i64> = {
                let mut stmt = self.conn.prepare(
                    "SELECT id FROM chunks WHERE embedding_v2 IS NULL AND embedding IS NOT NULL LIMIT ?1"
                )?;
                stmt.query_map([batch_size], |row| row.get(0))?
                    .collect::<std::result::Result<Vec<_>, _>>()?
            };

            if ids.is_empty() { break; }

            let tx = self.conn.unchecked_transaction()?;
            for id in &ids {
                // Read old embedding, convert format, write new
                let old_blob: Vec<u8> = tx.query_row(
                    "SELECT embedding FROM chunks WHERE id = ?1",
                    [id], |row| row.get(0),
                )?;
                let new_blob = convert_embedding_format(&old_blob)?;
                tx.execute(
                    "UPDATE chunks SET embedding_v2 = ?1 WHERE id = ?2",
                    rusqlite::params![new_blob, id],
                )?;
            }
            tx.commit()?;

            processed += ids.len() as i64;
            eprintln!("Migrated embeddings: {}/{}", processed, total);
        }

        // Step 3: After confirming all migrated, drop old column
        // (Requires table rebuild in SQLite)
        Ok(())
    }
}
```

Batch processing prevents a single massive transaction from locking the database. Each batch commits independently, so if the process crashes mid-migration, it resumes from where it left off (the `WHERE embedding_v2 IS NULL` filter). Run `VACUUM` after dropping the old column to reclaim space.

WAL mode is the key enabler. Readers don't block writers and vice versa. But you need to be careful with schema changes:

```rust
pub fn safe_concurrent_migration(db_path: &Path) -> Result<()> {
    let conn = rusqlite::Connection::open(db_path)?;
    conn.pragma_update(None, "journal_mode", "WAL")?;

    // Check if another process is mid-migration
    let lock_table_exists: bool = conn.query_row(
        "SELECT COUNT(*) > 0 FROM sqlite_master WHERE name = 'migration_lock'",
        [], |row| row.get(0),
    )?;

    if !lock_table_exists {
        conn.execute_batch(
            "CREATE TABLE IF NOT EXISTS migration_lock (
                id INTEGER PRIMARY KEY CHECK(id = 1),
                locked_by TEXT,
                locked_at INTEGER
            );"
        )?;
    }

    // Try to acquire migration lock (advisory lock pattern)
    let pid = std::process::id().to_string();
    let now = now_epoch();
    let acquired = conn.execute(
        "INSERT OR IGNORE INTO migration_lock (id, locked_by, locked_at) VALUES (1, ?1, ?2)",
        rusqlite::params![pid, now],
    )? > 0;

    if !acquired {
        // Check for stale lock (older than 5 minutes)
        let lock_age: i64 = conn.query_row(
            "SELECT ?1 - locked_at FROM migration_lock WHERE id = 1",
            [now], |row| row.get(0),
        ).unwrap_or(0);

        if lock_age > 300 {
            eprintln!("Breaking stale migration lock (age: {}s)", lock_age);
            conn.execute(
                "UPDATE migration_lock SET locked_by = ?1, locked_at = ?2 WHERE id = 1",
                rusqlite::params![pid, now],
            )?;
        } else {
            anyhow::bail!("Another process is running migrations. Waiting...");
        }
    }

    // Run migrations here...
    run_migrations(&conn)?;

    // Release lock
    conn.execute("DELETE FROM migration_lock WHERE id = 1", [])?;

    Ok(())
}
```

The advisory lock pattern prevents two processes from running migrations simultaneously. WAL mode means readers continue working while the migration runs -- they see the pre-migration schema until the migration commits, then automatically see the new schema. The stale lock timeout (5 minutes) handles the case where a process crashed mid-migration.

