            value     TEXT NOT NULL,
            stored_at INTEGER NOT NULL
        );
        CREATE UNIQUE INDEX idx_prefs_pk ON preferences(project, category, key);

        -- Phase 2: Copy data based on key prefix convention
        INSERT INTO facts (project, key, value, confidence, stored_at)
        SELECT project, key, value, confidence, stored_at
        FROM memory
        WHERE key NOT LIKE 'pref_%';

        INSERT INTO preferences (project, category, key, value, stored_at)
        SELECT project,
               CASE
                   WHEN key LIKE 'pref_editor_%' THEN 'editor'
                   WHEN key LIKE 'pref_format_%' THEN 'formatting'
                   ELSE 'general'
               END,
               REPLACE(key, 'pref_', ''),
