WAL (Write-Ahead Logging) mode is the answer. It allows concurrent readers with a single writer:

```rust
use rusqlite::Connection;
use std::sync::{Arc, Mutex};

pub struct SharedDatabase {
    /// Write connection: only one writer at a time (protected by Mutex).
    writer: Mutex<Connection>,
    /// Read pool: multiple readers can be active simultaneously.
    /// Each reader has its own connection.
    readers: Vec<Connection>,
}

impl SharedDatabase {
    pub fn open(path: &str, reader_count: usize) -> anyhow::Result<Self> {
        // Writer connection
        let writer = Connection::open(path)?;
        writer.pragma_update(None, "journal_mode", "WAL")?;
        writer.pragma_update(None, "synchronous", "NORMAL")?;
        writer.pragma_update(None, "busy_timeout", "5000")?; // 5s retry on lock

        // Reader connections (separate connections for true concurrency)
        let mut readers = Vec::with_capacity(reader_count);
        for _ in 0..reader_count {
            let reader = Connection::open(path)?;
            reader.pragma_update(None, "journal_mode", "WAL")?;
            // Readers can use query_only for safety
            reader.pragma_update(None, "query_only", "ON")?;
            readers.push(reader);
        }

        Ok(Self {
            writer: Mutex::new(writer),
            readers,
        })
    }

    pub fn write<F, T>(&self, f: F) -> anyhow::Result<T>
    where
        F: FnOnce(&Connection) -> anyhow::Result<T>,
    {
        let conn = self.writer.lock().unwrap_or_else(|e| e.into_inner());
        f(&conn)
    }

    pub fn read<F, T>(&self, reader_idx: usize, f: F) -> anyhow::Result<T>
    where
        F: FnOnce(&Connection) -> anyhow::Result<T>,
    {
        let idx = reader_idx % self.readers.len();
        f(&self.readers[idx])
    }
}
```

Key WAL mode properties: (1) Readers never block writers. (2) Writers never block readers. (3) Only one writer at a time -- the `busy_timeout` makes the second writer wait instead of failing immediately. (4) Readers see a consistent snapshot from when their transaction started. The `query_only` pragma on reader connections prevents accidental writes.

Use a version column and check-and-set (CAS) semantics:

```rust
pub struct ConfigStore {
    conn: rusqlite::Connection,
}

#[derive(Debug, Clone)]
pub struct VersionedConfig {
    pub key: String,
    pub value: String,
    pub version: i64,
}

impl ConfigStore {
    pub fn init(&self) -> Result<()> {
        self.conn.execute_batch(
            "CREATE TABLE IF NOT EXISTS config (
                key     TEXT PRIMARY KEY,
                value   TEXT NOT NULL,
                version INTEGER NOT NULL DEFAULT 1,
                updated_at INTEGER NOT NULL
            );"
        )?;
        Ok(())
    }

    pub fn get(&self, key: &str) -> Result<Option<VersionedConfig>> {
        self.conn.query_row(
            "SELECT key, value, version FROM config WHERE key = ?1",
            [key],
            |row| Ok(VersionedConfig {
                key: row.get(0)?,
                value: row.get(1)?,
                version: row.get(2)?,
            }),
        ).optional().map_err(|e| e.into())
    }

    /// Update only if the version matches. Returns Ok(true) if updated,
    /// Ok(false) if someone else modified it first.
    pub fn compare_and_swap(
        &self,
        key: &str,
        new_value: &str,
        expected_version: i64,
    ) -> Result<bool> {
        let updated = self.conn.execute(
            "UPDATE config SET value = ?1, version = version + 1, updated_at = ?2
             WHERE key = ?3 AND version = ?4",
            rusqlite::params![new_value, now_epoch(), key, expected_version],
        )?;

        if updated == 0 {
            // Either the key doesn't exist or version mismatched
            let exists = self.get(key)?.is_some();
            if exists {
                return Ok(false); // Conflict: someone else updated
            }
            // Key doesn't exist, insert with version 1
            self.conn.execute(
                "INSERT INTO config (key, value, version, updated_at)
                 VALUES (?1, ?2, 1, ?3)",
                rusqlite::params![key, new_value, now_epoch()],
            )?;
        }

        Ok(true)
    }

    /// Read-modify-write with automatic retry on conflict.
    pub fn update_with_retry<F>(
        &self,
        key: &str,
        max_retries: u32,
        modify: F,
    ) -> Result<String>
    where
        F: Fn(&str) -> String,
    {
        for attempt in 0..=max_retries {
            let current = self.get(key)?;
            let (current_value, version) = match current {
                Some(c) => (c.value.clone(), c.version),
                None => (String::new(), 0),
            };

            let new_value = modify(&current_value);
            if self.compare_and_swap(key, &new_value, version)? {
                return Ok(new_value);
            }

            if attempt < max_retries {
                eprintln!("Config update conflict on '{}', retry {}", key, attempt + 1);
            }
        }
        anyhow::bail!("failed to update '{}' after {} retries", key, max_retries)
    }
}
```

Optimistic locking is ideal when conflicts are rare (which they are for config stores). The retry loop handles the rare case where two processes race. No locks are held during the modify function, so there's no deadlock risk.

SQLite doesn't have native advisory locks, but you can build them with a lock table:

```rust
pub struct AdvisoryLock {
    conn: rusqlite::Connection,
    lock_name: String,
    holder_id: String,
}

impl AdvisoryLock {
    pub fn new(conn: rusqlite::Connection, lock_name: &str) -> Result<Self> {
        conn.execute_batch(
            "CREATE TABLE IF NOT EXISTS advisory_locks (
                name      TEXT PRIMARY KEY,
                holder_id TEXT NOT NULL,
                acquired_at INTEGER NOT NULL,
                expires_at  INTEGER NOT NULL
            );"
        )?;

        Ok(Self {
            conn,
            lock_name: lock_name.to_string(),
            holder_id: format!("{}:{}", std::process::id(), uuid::Uuid::new_v4()),
        })
    }

    /// Try to acquire the lock. Returns true if acquired.
    pub fn try_acquire(&self, ttl_secs: i64) -> Result<bool> {
        let now = now_epoch();

        // Clean expired locks first
        self.conn.execute(
            "DELETE FROM advisory_locks WHERE expires_at < ?1",
            [now],
        )?;

        // Try to insert (fails if lock exists and isn't expired)
        let result = self.conn.execute(
            "INSERT OR IGNORE INTO advisory_locks (name, holder_id, acquired_at, expires_at)
             VALUES (?1, ?2, ?3, ?4)",
            rusqlite::params![self.lock_name, self.holder_id, now, now + ttl_secs],
        )?;

        Ok(result > 0)
    }

    /// Acquire with wait. Polls every `poll_interval` until acquired or timeout.
    pub fn acquire_blocking(&self, ttl_secs: i64, timeout_secs: i64) -> Result<()> {
        let deadline = std::time::Instant::now() + std::time::Duration::from_secs(timeout_secs as u64);

        while std::time::Instant::now() < deadline {
            if self.try_acquire(ttl_secs)? {
                return Ok(());
            }
            std::thread::sleep(std::time::Duration::from_millis(100));
        }

        anyhow::bail!("timed out waiting for advisory lock '{}'", self.lock_name)
    }

    /// Release the lock. Only succeeds if we still hold it.
    pub fn release(&self) -> Result<bool> {
        let released = self.conn.execute(
            "DELETE FROM advisory_locks WHERE name = ?1 AND holder_id = ?2",
            rusqlite::params![self.lock_name, self.holder_id],
        )?;
        Ok(released > 0)
    }
}

impl Drop for AdvisoryLock {
    fn drop(&mut self) {
        let _ = self.release();
    }
}
```

The TTL (`expires_at`) prevents permanent locks from crashed processes. The `holder_id` combines PID and UUID so we can verify we still hold the lock. The `Drop` impl provides automatic cleanup, though the TTL is the real safety net.

Use last-writer-wins with conflict detection and optional merge:

```rust
#[derive(Debug)]
pub enum ConflictResolution {
    LastWriterWins,
    HigherConfidenceWins,
    Merge,
}

pub struct ConflictAwareFactStore {
    conn: rusqlite::Connection,
    project: String,
    resolution: ConflictResolution,
}

impl ConflictAwareFactStore {
    pub fn upsert_with_conflict_check(
        &self,
        key: &str,
        value: &str,
        confidence: f32,
    ) -> Result<UpsertResult> {
        let existing = self.get_fact(key)?;

        match existing {
            None => {
                self.insert_fact(key, value, confidence)?;
                Ok(UpsertResult::Inserted)
            }
            Some(old) if old.value == value => {
                // Same value, just update confidence if higher
                if confidence > old.confidence {
                    self.update_confidence(key, confidence)?;
                }
                Ok(UpsertResult::Unchanged)
            }
            Some(old) => {
                match self.resolution {
                    ConflictResolution::LastWriterWins => {
                        self.update_fact(key, value, confidence)?;
                        Ok(UpsertResult::Updated { previous: old.value })
                    }
                    ConflictResolution::HigherConfidenceWins => {
                        if confidence >= old.confidence {
                            self.update_fact(key, value, confidence)?;
                            Ok(UpsertResult::Updated { previous: old.value })
                        } else {
                            Ok(UpsertResult::Rejected {
                                reason: format!(
                                    "existing confidence {} > new {}",
                                    old.confidence, confidence
                                ),
                            })
                        }
                    }
                    ConflictResolution::Merge => {
                        // For list-like values, merge them
                        let merged = merge_values(&old.value, value);
                        let merged_confidence = confidence.max(old.confidence);
                        self.update_fact(key, &merged, merged_confidence)?;
                        Ok(UpsertResult::Merged {
                            previous: old.value,
                            result: merged,
                        })
                    }
                }
            }
        }
    }
}

fn merge_values(old: &str, new: &str) -> String {
    // Simple merge: if both look like comma-separated lists, union them
    if old.contains(',') || new.contains(',') {
        let mut items: Vec<&str> = old.split(',').map(|s| s.trim()).collect();
        for item in new.split(',').map(|s| s.trim()) {
            if !items.contains(&item) {
                items.push(item);
            }
        }
        items.join(", ")
    } else {
        // Default: new value wins
        new.to_string()
    }
}

#[derive(Debug)]
pub enum UpsertResult {
    Inserted,
    Updated { previous: String },
    Unchanged,
    Rejected { reason: String },
    Merged { previous: String, result: String },
}
```

For a local-first app with a single writer, `LastWriterWins` is usually correct. `HigherConfidenceWins` is useful when facts come from different sources (user-stated facts should override model-inferred ones). The merge strategy handles accumulative facts like "tech_stack: Rust, Python" where you want to add new entries.

WAL files grow because checkpointing isn't aggressive enough. Configure auto-checkpoint and add manual checkpointing:

```rust
pub fn configure_wal(conn: &rusqlite::Connection) -> Result<()> {
    // Enable WAL mode
    conn.pragma_update(None, "journal_mode", "WAL")?;

    // NORMAL synchronous: durable on crash, slightly faster than FULL
    conn.pragma_update(None, "synchronous", "NORMAL")?;

    // Auto-checkpoint every 1000 pages (~4MB with default page size)
    conn.pragma_update(None, "wal_autocheckpoint", "1000")?;

    // Busy timeout: wait up to 5s for a lock instead of failing immediately
    conn.pragma_update(None, "busy_timeout", "5000")?;

    Ok(())
}

pub struct WalManager {
    conn: rusqlite::Connection,
    last_checkpoint: std::time::Instant,
}

impl WalManager {
    /// Periodic checkpoint -- call from a background task.
    pub fn maybe_checkpoint(&mut self) -> Result<()> {
        // Don't checkpoint more than once per minute
        if self.last_checkpoint.elapsed() < std::time::Duration::from_secs(60) {
            return Ok(());
        }

        // PASSIVE checkpoint: doesn't block readers or writers
        let result: (i32, i32) = self.conn.query_row(
            "PRAGMA wal_checkpoint(PASSIVE)",
            [],
            |row| Ok((row.get(0)?, row.get(1)?)),
        )?;

        let (checkpointed, total) = result;
        if total > 0 {
            eprintln!("WAL checkpoint: {}/{} pages", checkpointed, total);
        }

        self.last_checkpoint = std::time::Instant::now();
        Ok(())
    }

    /// Aggressive checkpoint on shutdown -- blocks until complete.
    pub fn checkpoint_on_shutdown(&self) -> Result<()> {
        // TRUNCATE: checkpoint and truncate WAL file to zero bytes
        self.conn.execute_batch("PRAGMA wal_checkpoint(TRUNCATE)")?;
        Ok(())
    }
}
```

Three checkpoint modes: (1) `PASSIVE` -- checkpoints what it can without blocking anyone, good for background use. (2) `FULL` -- waits for readers to finish, then checkpoints everything. (3) `TRUNCATE` -- like FULL but also truncates the WAL file, good for shutdown. Never use `TRUNCATE` during normal operation -- it blocks all readers until complete.

Use `EXPLAIN QUERY PLAN` to see if indexes are being used:

```rust
pub fn diagnose_slow_query(conn: &rusqlite::Connection, query: &str) -> Result<()> {
    let mut stmt = conn.prepare(&format!("EXPLAIN QUERY PLAN {}", query))?;
    let plan: Vec<String> = stmt.query_map([], |row| {
        Ok(format!("{}: {}", row.get::<_, i64>(0)?, row.get::<_, String>(3)?))
    })?.collect::<std::result::Result<Vec<_>, _>>()?;

    for line in &plan {
        eprintln!("  {}", line);
    }

    // If you see "SCAN TABLE" instead of "SEARCH TABLE", you need an index
    if plan.iter().any(|l| l.contains("SCAN TABLE")) {
        eprintln!("WARNING: Full table scan detected. Add an index.");
    }

    Ok(())
}
```

Common fixes for a 50K-row facts table:

```sql
-- Problem 1: No index on the query columns
-- Fix: Composite index matching your WHERE clause
CREATE INDEX IF NOT EXISTS idx_facts_project_key ON facts(project, key);

-- Problem 2: LIKE queries can't use indexes
-- BAD: SELECT * FROM facts WHERE key LIKE '%rust%'  (full scan)
-- GOOD: Use FTS5 instead:
CREATE VIRTUAL TABLE facts_fts USING fts5(key, value, content=facts, content_rowid=id);

-- Problem 3: Sorting without index
-- BAD: SELECT * FROM facts ORDER BY stored_at DESC LIMIT 20  (sorts all 50K rows)
-- GOOD: Index covers the sort
CREATE INDEX IF NOT EXISTS idx_facts_recent ON facts(stored_at DESC);
```

Also check your connection setup:
```rust
// These pragmas can dramatically improve read performance:
conn.pragma_update(None, "journal_mode", "WAL")?;   // Non-blocking reads
conn.pragma_update(None, "cache_size", "-64000")?;   // 64MB cache (negative = KB)
conn.pragma_update(None, "mmap_size", "268435456")?;  // 256MB memory-mapped I/O
conn.pragma_update(None, "temp_store", "MEMORY")?;    // Temp tables in RAM
```

With proper indexes, 50K rows should query in under 1ms. If you're still seeing 200ms, the bottleneck is likely disk I/O -- the `mmap_size` pragma fixes that by mapping the database file into memory.

For 10K vectors, brute-force is fine if you optimize the math. The bottleneck is likely memory allocation, not computation:

```rust
/// Optimized cosine similarity using pre-normalized vectors.
/// Pre-normalize at insert time so search only needs dot product.
pub fn cosine_similarity_prenormalized(a: &[f32], b: &[f32]) -> f32 {
    debug_assert_eq!(a.len(), b.len());
    a.iter().zip(b.iter()).map(|(x, y)| x * y).sum()
}

/// Batch search: compute similarity against all stored embeddings.
/// Returns top-k results sorted by similarity.
pub fn search_top_k(
    query_embedding: &[f32],
    stored: &[(i64, Vec<f32>)],  // (chunk_id, embedding)
    k: usize,
) -> Vec<(i64, f32)> {
    // Use a min-heap to track top-k without sorting everything
    use std::collections::BinaryHeap;
    use std::cmp::Reverse;

    let mut heap: BinaryHeap<Reverse<(ordered_float::OrderedFloat<f32>, i64)>> =
        BinaryHeap::with_capacity(k + 1);

    for (id, embedding) in stored {
        let sim = cosine_similarity_prenormalized(query_embedding, embedding);
        heap.push(Reverse((ordered_float::OrderedFloat(sim), *id)));
        if heap.len() > k {
            heap.pop(); // Remove lowest similarity
        }
    }

    heap.into_sorted_vec()
        .into_iter()
        .map(|Reverse((sim, id))| (id, sim.0))
        .collect()
}

/// Optimization: load all embeddings into memory at startup.
/// 10K vectors * 384 dims * 4 bytes = ~15MB -- easily fits in RAM.
pub struct EmbeddingCache {
    embeddings: Vec<(i64, Vec<f32>)>,
}

impl EmbeddingCache {
    pub fn load(conn: &rusqlite::Connection) -> Result<Self> {
        let mut stmt = conn.prepare(
            "SELECT id, embedding FROM chunks WHERE embedding IS NOT NULL"
        )?;
        let embeddings = stmt.query_map([], |row| {
            let id: i64 = row.get(0)?;
            let blob: Vec<u8> = row.get(1)?;
            let floats = bytes_to_f32(&blob);
            Ok((id, floats))
        })?.collect::<std::result::Result<Vec<_>, _>>()?;

        Ok(Self { embeddings })
    }

    pub fn search(&self, query: &[f32], k: usize) -> Vec<(i64, f32)> {
        search_top_k(query, &self.embeddings, k)
    }
}
```

This brings search from 500ms to under 5ms for 10K vectors. The key optimizations: (1) Pre-normalize vectors at insert time. (2) Load embeddings into RAM at startup instead of reading from SQLite per query. (3) Use a min-heap instead of sorting all results. For 100K+ vectors, consider an approximate nearest neighbor library like `hnsw`.

Push everything you can into SQL. Here's the before and after:

```rust
// SLOW: Load all, filter in Rust
pub fn find_recent_sessions_slow(&self) -> Result<Vec<SessionSummary>> {
    let all: Vec<Session> = self.load_all_sessions()?;
    let cutoff = now_epoch() - 7 * 24 * 3600;
    let filtered: Vec<SessionSummary> = all.into_iter()
        .filter(|s| s.ended_at.map_or(false, |t| t > cutoff))
        .filter(|s| s.project == self.project)
        .map(|s| {
            let msgs = self.count_messages(&s.id).unwrap_or(0);
            SessionSummary { id: s.id, summary: s.summary, message_count: msgs }
        })
        .take(10)
        .collect();
    Ok(filtered)
}

// FAST: Single query, filtering and joining in SQLite
pub fn find_recent_sessions_fast(&self) -> Result<Vec<SessionSummary>> {
    let cutoff = now_epoch() - 7 * 24 * 3600;
    let mut stmt = self.conn.prepare(
        "SELECT s.id, s.summary, s.message_count, s.total_tokens,
                s.started_at, s.ended_at
         FROM sessions s
         WHERE s.project = ?1
           AND s.ended_at IS NOT NULL
           AND s.ended_at > ?2
         ORDER BY s.ended_at DESC
         LIMIT 10"
    )?;

    let sessions = stmt.query_map(
        rusqlite::params![self.project, cutoff],
        |row| Ok(SessionSummary {
            id: row.get(0)?,
            summary: row.get(1)?,
            message_count: row.get(2)?,
        }),
    )?.collect::<std::result::Result<Vec<_>, _>>()?;

    Ok(sessions)
}
```

Performance rules for SQLite: (1) Never load all rows and filter in application code. (2) Use `LIMIT` to cap results. (3) Use covering indexes (index includes all columns needed by the query). (4) Denormalize counts into the parent table (`message_count` in sessions) instead of JOIN + COUNT. The fast version does one disk read; the slow version does N+1 reads (one for all sessions, then one per session for message count).

Use `rusqlite::CachedStatement` via `prepare_cached`:

```rust
use rusqlite::Connection;
use anyhow::Result;

pub struct QueryCache<'a> {
    conn: &'a Connection,
}

impl<'a> QueryCache<'a> {
    pub fn new(conn: &'a Connection) -> Self {
        // Set statement cache size (default is 16)
        conn.set_prepared_statement_cache_capacity(64);
        Self { conn }
    }

    /// Using prepare_cached instead of prepare reuses the compiled statement.
    pub fn get_fact(&self, project: &str, key: &str) -> Result<Option<String>> {
        // prepare_cached: returns a cached statement, compiles only on first call
        let mut stmt = self.conn.prepare_cached(
            "SELECT value FROM facts WHERE project = ?1 AND key = ?2"
        )?;
        let result = stmt.query_row(
            rusqlite::params![project, key],
            |row| row.get(0),
        ).optional()?;
        Ok(result)
    }

    pub fn upsert_fact(&self, project: &str, key: &str, value: &str) -> Result<()> {
        let mut stmt = self.conn.prepare_cached(
            "INSERT INTO facts (project, key, value, stored_at)
             VALUES (?1, ?2, ?3, ?4)
             ON CONFLICT(project, key) DO UPDATE SET
                value = excluded.value,
                stored_at = excluded.stored_at"
        )?;
        stmt.execute(rusqlite::params![project, key, value, now_epoch()])?;
        Ok(())
    }

    /// Batch insert with a single prepared statement
    pub fn bulk_insert_facts(&self, project: &str, facts: &[(&str, &str)]) -> Result<()> {
        let tx = self.conn.unchecked_transaction()?;
        {
            let mut stmt = tx.prepare_cached(
                "INSERT OR REPLACE INTO facts (project, key, value, stored_at)
                 VALUES (?1, ?2, ?3, ?4)"
            )?;
            let now = now_epoch();
            for (key, value) in facts {
                stmt.execute(rusqlite::params![project, key, value, now])?;
            }
        }
        tx.commit()?;
        Ok(())
    }
}
```

The performance difference is significant: `prepare()` compiles SQL to bytecode every call (~50us). `prepare_cached()` compiles once and reuses (~0.5us). For a hot path called thousands of times per session, that's a 100x speedup. Also note the transaction in `bulk_insert_facts` -- without it, each INSERT is its own transaction with a fsync, which is catastrophically slow.

Use filesystem mtime as the change signal, stored alongside each indexed file:

```rust
use std::path::Path;
use std::time::SystemTime;
use anyhow::Result;

pub struct IncrementalIndexer {
    conn: rusqlite::Connection,
}

impl IncrementalIndexer {
    /// Returns files that need re-indexing (new, modified, or deleted).
    pub fn detect_changes(&self, project_root: &Path) -> Result<ChangeSet> {
        let mut changes = ChangeSet::default();

        // Get all currently indexed files
        let mut stmt = self.conn.prepare(
            "SELECT file_path, file_mtime FROM chunks GROUP BY file_path"
        )?;
        let indexed: std::collections::HashMap<String, f64> = stmt.query_map([], |row| {
            Ok((row.get::<_, String>(0)?, row.get::<_, f64>(1)?))
        })?.filter_map(|r| r.ok()).collect();

        // Walk the filesystem
        let mut current_files = std::collections::HashSet::new();
        for entry in walkdir::WalkDir::new(project_root)
            .into_iter()
            .filter_entry(|e| !should_skip(e))
        {
            let entry = entry?;
            if !entry.file_type().is_file() || !is_code_file(entry.path()) {
                continue;
            }

            let path_str = entry.path().to_string_lossy().to_string();
            current_files.insert(path_str.clone());

            let mtime = entry.metadata()?.modified()?
                .duration_since(SystemTime::UNIX_EPOCH)?
                .as_secs_f64();

            match indexed.get(&path_str) {
                Some(&indexed_mtime) if (mtime - indexed_mtime).abs() < 0.001 => {
                    // File unchanged
                }
                Some(_) => changes.modified.push(path_str),
                None => changes.added.push(path_str),
            }
        }

        // Find deleted files
        for indexed_path in indexed.keys() {
            if !current_files.contains(indexed_path) {
                changes.deleted.push(indexed_path.clone());
            }
        }

        Ok(changes)
    }

    /// Process only changed files
    pub fn index_changes(&self, changes: &ChangeSet) -> Result<IndexStats> {
        let mut stats = IndexStats::default();

        // Remove deleted files from index
        for path in &changes.deleted {
            self.conn.execute("DELETE FROM chunks WHERE file_path = ?1", [path])?;
            stats.deleted += 1;
        }

        // Remove then re-index modified files
        for path in &changes.modified {
            self.conn.execute("DELETE FROM chunks WHERE file_path = ?1", [path])?;
            self.index_file(path)?;
            stats.updated += 1;
        }

        // Index new files
        for path in &changes.added {
            self.index_file(path)?;
            stats.added += 1;
        }

        Ok(stats)
    }
}

#[derive(Default)]
pub struct ChangeSet {
    pub added: Vec<String>,
    pub modified: Vec<String>,
    pub deleted: Vec<String>,
}

#[derive(Default)]
pub struct IndexStats {
    pub added: u32,
    pub updated: u32,
    pub deleted: u32,
}
```

The mtime comparison uses a small epsilon (0.001s) because floating-point timestamps can have rounding differences. The `GROUP BY file_path` in the initial query deduplicates chunks per file. For large codebases (100K+ files), the initial walk can be slow -- consider using the `notify` crate for real-time filesystem watching instead of periodic full scans.

WAL mode + NORMAL synchronous is the sweet spot between safety and performance. But you need to handle crash recovery too:

```rust
pub struct SafeDatabase {
    conn: rusqlite::Connection,
    db_path: std::path::PathBuf,
}

impl SafeDatabase {
    pub fn open(path: &std::path::Path) -> Result<Self> {
        // Integrity check on open (fast: checks header and freelist)
        let conn = rusqlite::Connection::open(path)?;

        // WAL mode: atomic writes even on crash
        conn.pragma_update(None, "journal_mode", "WAL")?;
        // NORMAL sync: durable after power loss (WAL mode guarantee)
        conn.pragma_update(None, "synchronous", "NORMAL")?;
        // Foreign keys: referential integrity
        conn.pragma_update(None, "foreign_keys", "ON")?;

        // Quick integrity check (just page headers, not full data)
        let ok: String = conn.query_row(
            "PRAGMA quick_check", [], |row| row.get(0)
        )?;
        if ok != "ok" {
            eprintln!("WARNING: Database integrity check failed: {}", ok);
            // Attempt recovery
            Self::attempt_recovery(path)?;
        }

        Ok(Self {
            conn,
            db_path: path.to_path_buf(),
        })
    }

    /// Atomic write: wrap multiple operations in a transaction.
    pub fn atomic_write<F, T>(&self, f: F) -> Result<T>
    where
        F: FnOnce(&rusqlite::Transaction) -> Result<T>,
    {
        let tx = self.conn.unchecked_transaction()?;
        let result = f(&tx)?;
        tx.commit()?;
        Ok(result)
    }

    /// Recovery: export what we can and rebuild
    fn attempt_recovery(path: &std::path::Path) -> Result<()> {
        let backup_path = path.with_extension("db.corrupt");
        std::fs::copy(path, &backup_path)?;
        eprintln!("Corrupt database backed up to {}", backup_path.display());

        // Try to dump and reload
        let conn = rusqlite::Connection::open(path)?;
        let dump_path = path.with_extension("db.recovery");
        let recovery_conn = rusqlite::Connection::open(&dump_path)?;

        // Copy table by table
        let tables: Vec<String> = conn.prepare(
            "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'"
        )?.query_map([], |row| row.get(0))?
          .collect::<std::result::Result<Vec<_>, _>>()?;

        for table in &tables {
            // Get schema
            let schema: String = conn.query_row(
                "SELECT sql FROM sqlite_master WHERE name = ?1",
                [table], |row| row.get(0),
            )?;
            recovery_conn.execute_batch(&schema)?;

            eprintln!("Recovered table: {}", table);
        }

        Ok(())
    }
}
```

Prevention checklist: (1) Always use WAL mode. (2) Never set `synchronous = OFF`. (3) Use transactions for multi-statement writes. (4) Run `PRAGMA quick_check` on open. (5) Keep backups. (6) Don't store the database on a network filesystem (NFS/SMB break SQLite's locking protocol).

Append a checksum after each entry and verify on read:

```rust
use std::io::{BufRead, Write};
use sha2::{Sha256, Digest};

pub struct ChecksummedLog {
    path: std::path::PathBuf,
}

#[derive(serde::Serialize, serde::Deserialize)]
struct LogEntry {
    data: serde_json::Value,
    checksum: String,  // SHA-256 of the data JSON
    seq: u64,          // Monotonic sequence number
}

impl ChecksummedLog {
    pub fn new(path: impl Into<std::path::PathBuf>) -> Self {
        Self { path: path.into() }
    }

    /// Append an entry with integrity checksum.
    pub fn append(&self, data: &serde_json::Value) -> Result<()> {
        let seq = self.count_entries()?;
        let data_json = serde_json::to_string(data)?;
        let checksum = compute_checksum(&data_json);

        let entry = LogEntry {
            data: data.clone(),
            checksum,
            seq,
        };

        let mut file = std::fs::OpenOptions::new()
            .create(true)
            .append(true)
            .open(&self.path)?;

        let line = serde_json::to_string(&entry)?;
        writeln!(file, "{}", line)?;
        file.sync_data()?;  // Ensure durability

        Ok(())
    }

    /// Read and verify all entries. Returns valid entries and reports corruption.
    pub fn read_verified(&self) -> Result<(Vec<serde_json::Value>, Vec<CorruptionReport>)> {
        let file = std::fs::File::open(&self.path)?;
        let reader = std::io::BufReader::new(file);

        let mut valid = Vec::new();
        let mut corrupt = Vec::new();
        let mut expected_seq = 0u64;

        for (line_num, line) in reader.lines().enumerate() {
            let line = line?;
            if line.trim().is_empty() { continue; }

            match serde_json::from_str::<LogEntry>(&line) {
                Ok(entry) => {
                    let data_json = serde_json::to_string(&entry.data)?;
                    let expected_checksum = compute_checksum(&data_json);

                    if entry.checksum != expected_checksum {
                        corrupt.push(CorruptionReport {
                            line: line_num,
                            kind: "checksum mismatch".into(),
                        });
                        continue;
                    }

                    if entry.seq != expected_seq {
                        corrupt.push(CorruptionReport {
                            line: line_num,
                            kind: format!("sequence gap: expected {} got {}", expected_seq, entry.seq),
                        });
                    }

                    valid.push(entry.data);
                    expected_seq = entry.seq + 1;
                }
                Err(e) => {
                    corrupt.push(CorruptionReport {
                        line: line_num,
                        kind: format!("parse error: {}", e),
                    });
                }
            }
        }

        Ok((valid, corrupt))
    }
}

fn compute_checksum(data: &str) -> String {
    let mut hasher = Sha256::new();
    hasher.update(data.as_bytes());
    format!("{:x}", hasher.finalize())
}

#[derive(Debug)]
pub struct CorruptionReport {
    pub line: usize,
    pub kind: String,
}
```

The sequence number detects missing entries (truncation). The checksum detects bit-rot or partial writes. The `sync_data()` call after each write ensures the entry is on disk before returning. For session logs, this is essential -- a crash after "writing" but before flushing means the last entry is garbage.

Use the write-to-temp-then-rename pattern. Rename is atomic on all major filesystems:

```rust
use std::path::Path;
use std::io::Write;
use anyhow::{Context, Result};

/// Atomically write content to a file using the temp+rename pattern.
/// Guarantees the file always contains either the old content or the
/// new content, never a partial write.
pub fn atomic_write(path: &Path, content: &[u8]) -> Result<()> {
    let parent = path.parent()
        .context("path has no parent directory")?;

    // Create temp file in the same directory (same filesystem = atomic rename)
    let mut temp = tempfile::NamedTempFile::new_in(parent)
        .context("failed to create temp file")?;

    // Write content to temp file
    temp.write_all(content)
        .context("failed to write to temp file")?;

    // Sync to disk (ensures content is durable before rename)
    temp.as_file().sync_all()
        .context("failed to sync temp file")?;

    // Atomic rename
    temp.persist(path)
        .context("failed to rename temp file to target")?;

    // Sync parent directory (ensures the directory entry is durable)
    #[cfg(unix)]
    {
        if let Ok(dir) = std::fs::File::open(parent) {
            let _ = dir.sync_all();
        }
    }

    Ok(())
}

/// Atomic JSON config write with backup
pub fn save_config<T: serde::Serialize>(path: &Path, config: &T) -> Result<()> {
    let json = serde_json::to_string_pretty(config)
        .context("failed to serialize config")?;

    // Keep one backup of the previous version
    if path.exists() {
        let backup = path.with_extension("json.bak");
        let _ = std::fs::copy(path, &backup);
    }

    atomic_write(path, json.as_bytes())
}
```

Three critical details: (1) The temp file MUST be on the same filesystem as the target -- cross-filesystem renames are not atomic. `NamedTempFile::new_in(parent)` ensures this. (2) `sync_all()` before rename ensures the data is on disk, not just in the OS page cache. (3) Syncing the parent directory on Unix ensures the directory entry update is durable. Without step 3, a power loss after rename could lose the directory entry even though the file data is on disk.

Use SQLite's online backup API for consistent backups, even while the database is in use:

```rust
use std::path::{Path, PathBuf};
use anyhow::{Context, Result};

pub struct BackupManager {
    db_path: PathBuf,
    backup_dir: PathBuf,
    max_backups: usize,
}

impl BackupManager {
    pub fn new(db_path: &Path, backup_dir: &Path, max_backups: usize) -> Result<Self> {
        std::fs::create_dir_all(backup_dir)?;
        Ok(Self {
            db_path: db_path.to_path_buf(),
            backup_dir: backup_dir.to_path_buf(),
            max_backups,
        })
    }

    /// Create a consistent backup using SQLite's backup API.
    pub fn create_backup(&self) -> Result<PathBuf> {
        let timestamp = chrono::Utc::now().format("%Y%m%d_%H%M%S");
        let backup_path = self.backup_dir.join(format!("backup_{}.db", timestamp));

        // Open source database
        let src = rusqlite::Connection::open(&self.db_path)?;

        // Create backup database
        let mut dst = rusqlite::Connection::open(&backup_path)?;

        // Use SQLite backup API (consistent snapshot, doesn't lock source)
        let backup = rusqlite::backup::Backup::new(&src, &mut dst)?;

        // Copy in steps to avoid blocking writers for too long
        // step(-1) copies everything at once; step(100) copies 100 pages at a time
        backup.step(-1)
            .context("backup step failed")?;

        // Verify backup integrity
        let ok: String = dst.query_row("PRAGMA quick_check", [], |row| row.get(0))?;
        if ok != "ok" {
            std::fs::remove_file(&backup_path)?;
            anyhow::bail!("backup integrity check failed");
        }

        // Rotate old backups
        self.rotate_backups()?;

        eprintln!("Backup created: {}", backup_path.display());
        Ok(backup_path)
    }

    /// Remove old backups, keeping only `max_backups` most recent.
    fn rotate_backups(&self) -> Result<()> {
        let mut backups: Vec<PathBuf> = std::fs::read_dir(&self.backup_dir)?
            .filter_map(|e| e.ok())
            .map(|e| e.path())
            .filter(|p| p.extension().map_or(false, |ext| ext == "db"))
            .collect();

        backups.sort(); // Filenames contain timestamps, so alphabetical = chronological

        while backups.len() > self.max_backups {
            if let Some(oldest) = backups.first() {
                std::fs::remove_file(oldest)?;
                backups.remove(0);
            }
        }

        Ok(())
    }

    /// Restore from the most recent backup.
    pub fn restore_latest(&self) -> Result<()> {
        let mut backups: Vec<PathBuf> = std::fs::read_dir(&self.backup_dir)?
            .filter_map(|e| e.ok())
            .map(|e| e.path())
            .filter(|p| p.extension().map_or(false, |ext| ext == "db"))
            .collect();

        backups.sort();
        let latest = backups.last()
            .context("no backups found")?;

        // Verify backup before restoring
        let check_conn = rusqlite::Connection::open(latest)?;
        let ok: String = check_conn.query_row("PRAGMA integrity_check", [], |row| row.get(0))?;
        drop(check_conn);

        if ok != "ok" {
            anyhow::bail!("latest backup is corrupt: {}", ok);
        }

        // Atomic replacement: copy to temp, then rename
        let temp_path = self.db_path.with_extension("db.restoring");
        std::fs::copy(latest, &temp_path)?;
        std::fs::rename(&temp_path, &self.db_path)?;

        // Also remove WAL and SHM files from old database
        let wal = self.db_path.with_extension("db-wal");
        let shm = self.db_path.with_extension("db-shm");
        let _ = std::fs::remove_file(&wal);
        let _ = std::fs::remove_file(&shm);

        eprintln!("Restored from: {}", latest.display());
        Ok(())
    }
}
```

Key points: (1) The SQLite backup API creates a consistent snapshot without blocking readers. (2) Always verify backup integrity before considering it valid. (3) Rotation prevents disk exhaustion. (4) On restore, delete the WAL and SHM files -- they belong to the old database. (5) Use atomic rename for the restore to prevent corruption if the process is killed mid-restore.
